import{_ as e,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"索引映射与文档模型","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/11-ElasticSearch学习/02-索引映射与文档模型.md","filePath":"语言/java/11-ElasticSearch学习/02-索引映射与文档模型.md","lastUpdated":1776149370000}'),t={name:"语言/java/11-ElasticSearch学习/02-索引映射与文档模型.md"};function n(_,a,d,h,o,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="索引映射与文档模型" tabindex="-1">索引映射与文档模型 <a class="header-anchor" href="#索引映射与文档模型" aria-label="Permalink to “索引映射与文档模型”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>索引映射决定字段如何被存储、分词和查询，文档模型则决定业务数据怎样组织到 ES 中。<br> 这是搜索系统设计质量的关键部分。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>很多查询慢、聚合差、排序异常，本质上都和 mapping 设计不合理有关。<br> 文档建模做得好，后续查询和分析都会更顺。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>mapping</li><li>text 与 keyword</li><li>date、numeric、boolean</li><li>nested 与 object</li><li>文档冗余与反规范化</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解字段类型直接决定查询行为</li><li>理解搜索系统更强调读模型设计</li><li>理解 ES 文档建模常常不是数据库表结构直接映射</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>所有字符串字段都用 text</li><li>直接照搬关系型表结构</li><li>忽视 nested 带来的查询和成本差异</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>为商品搜索场景设计一套 mapping</li><li>对比 text 和 keyword 的查询差异</li><li>总结 object 和 nested 的使用边界</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>text 和 keyword 分别适合什么场景</li><li>为什么 ES 文档建模常常要反规范化</li><li>nested 为什么不能乱用</li></ul>',15)])])}const b=e(t,[["render",n]]);export{p as __pageData,b as default};
